// Profile.jsx
import React from "react";
import { useNavigate } from "react-router-dom";

export default function Profile() {
  const nav = useNavigate();

  // If you store employee in localStorage, you could validate here.
  // For now just redirect to dashboard.
  React.useEffect(() => {
    nav("/dashboard");
  }, [nav]);

  return <div style={{ padding: 30 }}>Redirecting to Dashboard...</div>;
}
